import React from 'react';
import { motion } from 'framer-motion';
import { useUser } from '../hooks/useUser';

interface HeaderProps {
  stars: number;
}

const Header: React.FC<HeaderProps> = ({ stars }) => {
  const { user } = useUser();
  const firstName = user?.first_name || 'Cadimurx';
  // Берём первую букву имени для аватара-заглушки
  const initial = firstName.charAt(0).toUpperCase();

  return (
    <motion.header
      className="app-header"
      initial={{ y: -50, opacity: 0 }}
      animate={{ y: 0, opacity: 1 }}
      transition={{ type: 'spring', stiffness: 300 }}
    >
      <div className="header-left">
        <div className="user-info">
          <div className="avatar">{initial}</div>
          <span className="username">{firstName}</span>
        </div>
      </div>

      <div className="header-center">
        <span className="logo">FazerCases</span>
      </div>

      <div className="header-right">
        <div className="balance">
          <span className="balance-icon">⭐</span>
          <span className="balance-amount">{stars}</span>
        </div>
      </div>
    </motion.header>
  );
};

export default Header;
